// Minimal jsdiff-like implementation: exposes Diff.diffLines(oldStr, newStr)
// Uses a simple LCS-based algorithm to compute line differences.
(function (root) {
  function diffLines(oldStr, newStr) {
    var oldLines = String(oldStr == null ? '' : oldStr).split('\n');
    var newLines = String(newStr == null ? '' : newStr).split('\n');
    var n = oldLines.length;
    var m = newLines.length;

    // LCS DP matrix
    var dp = new Array(n + 1);
    for (var i = 0; i <= n; i++) {
      dp[i] = new Array(m + 1);
      for (var j = 0; j <= m; j++) {
        dp[i][j] = 0;
      }
    }

    for (i = 1; i <= n; i++) {
      for (j = 1; j <= m; j++) {
        if (oldLines[i - 1] === newLines[j - 1]) {
          dp[i][j] = dp[i - 1][j - 1] + 1;
        } else {
          dp[i][j] = dp[i - 1][j] >= dp[i][j - 1] ? dp[i - 1][j] : dp[i][j - 1];
        }
      }
    }

    // Backtrack to build diff parts
    var parts = [];
    i = n;
    j = m;
    while (i > 0 || j > 0) {
      if (i > 0 && j > 0 && oldLines[i - 1] === newLines[j - 1]) {
        parts.push({ value: oldLines[i - 1] + '\n' });
        i--;
        j--;
      } else if (j > 0 && (i === 0 || dp[i][j - 1] >= dp[i - 1][j])) {
        parts.push({ value: newLines[j - 1] + '\n', added: true });
        j--;
      } else if (i > 0 && (j === 0 || dp[i - 1][j] > dp[i][j - 1])) {
        parts.push({ value: oldLines[i - 1] + '\n', removed: true });
        i--;
      } else {
        // Fallback (shouldn't normally hit)
        i--;
        j--;
      }
    }

    parts.reverse();

    // Merge consecutive parts of same type
    var merged = [];
    for (var k = 0; k < parts.length; k++) {
      var p = parts[k];
      if (!merged.length) {
        merged.push(p);
      } else {
        var last = merged[merged.length - 1];
        var lastType = (last.added ? 'added' : last.removed ? 'removed' : 'equal');
        var curType = (p.added ? 'added' : p.removed ? 'removed' : 'equal');
        if (lastType === curType) {
          last.value += p.value;
        } else {
          merged.push(p);
        }
      }
    }

    return merged;
  }

  root.Diff = {
    diffLines: diffLines
  };
})(this);

